INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'pain_point', 3, 'vi', '⚠️', 'Sợ bị lừa – hàng giả, hàng kém chất lượng', 'Ảnh 1 sao hàng thực tế 0 sao. Hàng trăm đô la bay đi không dấu vết.', '{}');
