INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'pain_point', 4, 'en', '💸', 'Wrong item, no return possible', 'Wrong or defective goods arrive and returning is impossible due to distance and language barriers.', '{}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'pain_point', 4, 'vi', '💸', 'Hàng sai – không thể hoàn trả', 'Hàng sai hoặc lỗi muốn đổi trả không được vì khoảng cách quá xa và bất đồng ngôn ngữ.', '{}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'pain_point', 4, 'zh', '💸', '收到错误商品，无法退货', '收到错误或有缺陷的商品，由于距离和语言障碍无法退货。', '{}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'pain_point', 5, 'en', '🔄', 'Must route through Vietnam first', 'Inspecting in Vietnam before shipping to USA wastes 3–4 extra weeks and $150–300 in unnecessary shipping fees.', '{}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'pain_point', 5, 'vi', '🔄', 'Phải chuyển vòng qua Việt Nam', 'Hàng về Việt Nam kiểm tra xong mới dám gửi đi Mỹ – tốn thêm 3–4 tuần và hàng trăm USD phí vô ích.', '{}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'pain_point', 5, 'zh', '🔄', '必须先经越南中转', '在越南检查后再寄美国，多浪费3-4周和150-300美元。', '{}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'pain_point', 6, 'en', '🕰️', 'Zero updates, weeks of silence', 'Order placed, then nothing. No tracking, no communication – weeks of anxious waiting.', '{}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'pain_point', 6, 'vi', '🕰️', 'Chờ đợi mòn mỏi, không ai cập nhật', 'Đặt hàng xong rơi vào im lặng. Không biết hàng đang ở đâu – lo lắng suốt cả tháng trời.', '{}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'pain_point', 6, 'zh', '🕰️', '零更新，数周无音讯', '下单后杳无音讯。没有跟踪，没有沟通——焦虑等待数周。', '{}');
