INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'process_step', 3, 'vi', '🛒', 'Đặt hàng & Thanh toán', 'Bạn xác nhận, THG đặt hàng bằng tiếng Trung – không cần bạn làm gì thêm', '{"num":3}');
