INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'process_step', 5, 'en', '🏠', 'Delivered in USA', 'Shipped directly to your US address, real-time tracking all the way', '{"num":5}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'process_step', 5, 'vi', '🏠', 'Giao tận nhà ở Mỹ', 'Ship thẳng đến địa chỉ tại Hoa Kỳ, tracking real-time liên tục cập nhật', '{"num":5}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'process_step', 5, 'zh', '🏠', '送达美国', '直接发到您的美国地址，全程实时跟踪', '{"num":5}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 1, 'en', '🛡️', 'Real address. Real business. Proven track record.', 'THG Fulfill is a registered business with offices in HCMC, warehouses in Guangdong (China), Milford PA & Winston-Salem NC. Thousands of successful orders.', '{"tag":"Trust & Safety"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 1, 'vi', '🛡️', 'Đơn vị có địa chỉ thực, hoạt động minh bạch', 'THG Fulfill có văn phòng tại TP.HCM, kho tại Trung Quốc và Mỹ. Hàng nghìn đơn hàng thành công.', '{"tag":"Uy tín & An toàn"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 1, 'zh', '🛡️', '真实地址，真实企业，过往业绩', 'THG Fulfill是注册企业，办公室在胡志明市，仓库在广东（中国）、宾州和北卡。数千成功订单。', '{"tag":"信任与安全"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 2, 'en', '🇨🇳', 'We negotiate directly with Chinese suppliers for you', 'Our team handles all communication in Mandarin – price negotiation, quality requests, and dispute resolution. You don''t need to know a single Chinese character.', '{"tag":"Mandarin Fluent"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 2, 'vi', '🇨🇳', 'Đội ngũ đàm phán trực tiếp với nhà cung cấp China', 'Chúng tôi thương lượng giá, xác minh nhà cung cấp và xử lý toàn bộ bằng tiếng Trung. Bạn không cần biết nửa chữ tiếng Trung.', '{"tag":"Đàm phán trung gian"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 2, 'zh', '🇨🇳', '我们直接用中文与供应商谈判', '我们的团队用中文处理所有沟通——议价、质量要求和纠纷解决。您不需要认识任何中文。', '{"tag":"精通中文"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 3, 'en', '📹', 'See your goods before they ship – no surprises', '100% of orders are inspected and video-recorded before packing. You review the video, approve, then we ship. Fully transparent.', '{"tag":"Video Inspection"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 3, 'vi', '📹', 'Xem video trước khi ship – không bao giờ bị bất ngờ', '100% đơn hàng được kiểm tra và quay video chi tiết trước khi đóng gói. Bạn xem, xác nhận rồi THG mới gửi đi.', '{"tag":"Video kiểm hàng thực tế"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 3, 'zh', '📹', '发货前看到您的商品——没有意外', '100%订单在包装前进行检查和录像。您审核视频、确认后我们才发货。完全透明。', '{"tag":"视频验货"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 4, 'en', '↩️', 'Defective goods? THG refunds or reships – free', 'If goods don''t match description or are defective, THG takes full responsibility – we work with the Chinese supplier to refund or send new goods at no cost.', '{"tag":"Buyer Protection"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 4, 'vi', '↩️', 'Hàng lỗi – THG hoàn tiền hoặc gửi lại miễn phí', 'Nếu hàng không đúng mô tả hoặc bị lỗi, THG chịu trách nhiệm hoàn toàn – làm việc với nhà cung cấp để hoàn tiền hoặc gửi lại hàng mới.', '{"tag":"Bảo vệ quyền lợi"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 4, 'zh', '↩️', '商品有缺陷？THG免费退款或重新发货', '如果商品与描述不符或有缺陷，THG承担全部责任——与供应商协商退款或免费重发。', '{"tag":"买家保障"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 5, 'en', '✈️', 'Skip the Vietnam detour. Save 3–4 weeks & $150–300', 'THG has warehouses in Guangdong (China), Milford PA & Winston-Salem NC. Goods inspected at China warehouse, then shipped directly to your US address.', '{"tag":"China → USA Direct"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 5, 'vi', '✈️', 'Không cần vòng qua Việt Nam – tiết kiệm 3–4 tuần', 'THG có kho tại Đông Hoản (Trung Quốc), Milford PA & Winston-Salem NC. Hàng kiểm tra tại China rồi ship thẳng đến địa chỉ Mỹ.', '{"tag":"Ship thẳng China → USA"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 5, 'zh', '✈️', '跳过越南中转，节省3-4周和150-300美元', 'THG在广东（中国）、宾州和北卡设有仓库。货物在中国仓库检查后直接发往您的美国地址。', '{"tag":"中国直邮美国"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 6, 'en', '📡', 'Always know where your package is', 'Updates via Facebook, Messenger, or email. You don''t have to ask – we proactively notify you at every step until your package arrives.', '{"tag":"Real-time Tracking"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 6, 'vi', '📡', 'Biết hàng đang ở đâu – cập nhật chủ động mọi lúc', 'Cập nhật qua Facebook, Messenger hoặc email. Không cần bạn hỏi – THG chủ động thông báo từng bước đến khi hàng gõ cửa nhà bạn.', '{"tag":"Tracking Real-time"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'solution', 6, 'zh', '📡', '随时知道包裹在哪里', '通过Facebook、Messenger或邮件更新。无需您询问——我们在每个步骤主动通知您。', '{"tag":"实时追踪"}');
