INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'shipping_lane', 1, 'zh', '✈️', 'Epacket – 最适合小包裹', '', '{"tag":"标准空运","time":"6-12个工作日","features":["重量：每件0.1-30公斤","USPS追踪送货上门","已含税（云途渠道）","适合：服装、配饰、小电子产品、家居用品","按公斤计价"],"note":"BSD = 工作日（周一至周五，不含节假日）"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'shipping_lane', 2, 'en', '🚀', 'DHL / Express – Fastest option', '', '{"tag":"Express Air","time":"3–5 BSD","features":["Fastest delivery to USA","Ideal for urgent orders or high-value goods","DHL / FedEx tracking – world-class reliability","Higher cost per kg vs. standard air","Best for: time-sensitive, lightweight, high-value items"],"note":"Contact THG for exact express quote"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'shipping_lane', 2, 'vi', '🚀', 'DHL / Express – Nhanh nhất', '', '{"tag":"Hàng không nhanh","time":"3–5 Ngày LV","features":["Nhanh nhất đến Mỹ","Lý tưởng cho đơn hàng khẩn hoặc hàng giá trị cao","Tracking DHL / FedEx – độ tin cậy cao","Giá cao hơn line thường","Phù hợp: hàng khẩn, nhẹ, giá trị cao"],"note":"Liên hệ THG để được báo giá express chính xác"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'shipping_lane', 2, 'zh', '🚀', 'DHL/快递 – 最快选项', '', '{"tag":"快速空运","time":"3-5个工作日","features":["最快送达美国","适合紧急订单或高价值商品","DHL/FedEx追踪——世界级可靠","每公斤成本高于标准空运","适合：时效性强、轻量、高价值物品"],"note":"联系THG获取准确快递报价"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'shipping_lane', 3, 'en', '🚢', 'Bulk Sea – Best price for heavy cargo', '', '{"tag":"Sea Freight","time":"20–25 BSD","features":["Minimum: 12 kg per package","Cheapest per-kg cost – ideal for bulk orders","Price tiers: 12 kg+, 21 kg+, 71 kg+, 100 kg+","Best for: furniture, machinery, large household items","Longer transit – plan ahead"],"note":"Volume weight: Length × Width × Height ÷ 6000"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'shipping_lane', 3, 'vi', '🚢', 'Hàng Lô Biển – Giá tốt nhất cho hàng nặng', '', '{"tag":"Đường biển","time":"20–25 Ngày LV","features":["Trọng lượng tối thiểu: 12 kg/kiện","Giá tốt nhất mỗi kg – lý tưởng cho hàng số lượng lớn","Giảm giá theo khối lượng: 12kg+, 21kg+, 71kg+, 100kg+","Phù hợp: nội thất, máy móc, hàng gia dụng lớn","Thời gian dài hơn – cần lên kế hoạch trước"],"note":"Trọng lượng thể tích: Dài × Rộng × Cao ÷ 6000"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'shipping_lane', 3, 'zh', '🚢', '散货海运 – 重货最优价', '', '{"tag":"海运","time":"20-25个工作日","features":["最低：每件12公斤","每公斤最便宜——适合大批量订单","价格阶梯：12kg+、21kg+、71kg+、100kg+","适合：家具、机械、大型家居用品","运输时间较长——需提前计划"],"note":"体积重量：长×宽×高÷6000"}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'policy', 1, 'en', '💰', 'THG compensates if things go wrong', '', '{"tag":"Compensation Policy","items":["✅ Delayed 20+ BSD due to THG error → 100% shipping refund","✅ Lost / damaged small package → Up to $20–$50/order compensation","✅ Bulk goods lost in transit → $5/kg compensation","✅ Refund to account within 15 business days"]}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'policy', 1, 'vi', '💰', 'THG cam kết bồi thường nếu có sự cố', '', '{"tag":"Chính sách đền bù","items":["✅ Chậm hơn 20 ngày làm việc do lỗi THG → Hoàn 100% phí vận chuyển","✅ Hàng lẻ thất lạc, hư hỏng → Đền bù tối đa $20–$50/đơn","✅ Hàng lô mất trong vận chuyển → Bồi thường $5/kg","✅ Hoàn tiền về tài khoản trong vòng 15 ngày làm việc"]}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'policy', 1, 'zh', '💰', 'THG出问题时赔偿', '', '{"tag":"赔偿政策","items":["✅ 因THG失误延迟20+工作日 → 100%退运费","✅ 小包丢失/损坏 → 最高$20-$50/单赔偿","✅ 散货运输中丢失 → $5/kg赔偿","✅ 15个工作日内退款到账"]}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'policy', 2, 'en', '🚫', 'Items we cannot ship', '', '{"tag":"Prohibited Goods","items":["⛔ Explosives, weapons, radioactive materials","⛔ Flammable materials, gas lighters","⛔ Narcotics, controlled substances","⛔ Pharmaceuticals, liquids, powders (some lanes)","⛔ Currency, financial documents","⛔ Animal products, natural wood"]}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'policy', 2, 'vi', '🚫', 'Danh mục hàng cấm – vui lòng kiểm tra trước', '', '{"tag":"Hàng cấm vận chuyển","items":["⛔ Chất nổ, vũ khí, vật liệu phóng xạ","⛔ Chất dễ cháy, bật lửa có gas/xăng","⛔ Chất gây nghiện, kích thích","⛔ Dược phẩm, chất lỏng, bột (một số line)","⛔ Tiền tệ, tài liệu tài chính","⛔ Sản phẩm từ động vật, gỗ tự nhiên"]}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'policy', 2, 'zh', '🚫', '我们无法运输的物品', '', '{"tag":"禁运物品","items":["⛔ 爆炸物、武器、放射性物质","⛔ 易燃物、气体打火机","⛔ 毒品、管制物质","⛔ 药品、液体、粉末（部分渠道）","⛔ 货币、金融文件","⛔ 动物制品、天然木材"]}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'policy', 3, 'en', '📋', 'Important things to know before ordering', '', '{"tag":"Key Terms","items":["📌 Delivery times are estimates – excludes weekends, holidays & force majeure","📌 Customer is responsible for accurate goods declaration","📌 Tracking inactive 21+ days → investigated as lost","📌 THG does not offer return-to-Vietnam / China service","📌 Fragile goods: customer must ensure adequate protective packaging"]}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'policy', 3, 'vi', '📋', 'Một số điểm bạn cần lưu ý', '', '{"tag":"Điều khoản quan trọng","items":["📌 Thời gian giao hàng là ước tính – không tính cuối tuần, lễ, bất khả kháng","📌 Khách hàng chịu trách nhiệm khai báo đúng thông tin hàng hóa","📌 Tracking quá 21 ngày không hoạt động → xem xét thất lạc","📌 THG không cung cấp dịch vụ trả hàng về Việt Nam / Trung Quốc","📌 Hàng dễ vỡ: khách hàng tự đảm bảo đóng gói chống sốc"]}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'policy', 3, 'zh', '📋', '下单前需要了解的重要事项', '', '{"tag":"重要条款","items":["📌 交货时间为估计值——不含周末、节假日和不可抗力","📌 客户负责准确申报货物信息","📌 追踪21+天无更新 → 视为丢失调查","📌 THG不提供退回越南/中国服务","📌 易碎品：客户须确保充分防护包装"]}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'policy', 4, 'en', '📣', 'Fast, transparent claims resolution', '', '{"tag":"Claims Process","items":["⏱️ Lost goods: claim within 2 months of ship date","⏱️ Damaged / price disputes: claim within 3 days of delivery","⚡ THG resolves claims within 7–20 business days","💬 Contact directly via Facebook or Hotline for fastest support"]}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'policy', 4, 'vi', '📣', 'Quy trình khiếu nại nhanh chóng', '', '{"tag":"Khiếu nại & Giải quyết","items":["⏱️ Mất hàng: Khiếu nại trong vòng 2 tháng kể từ ngày ship","⏱️ Hư hỏng / giá cước: Trong vòng 3 ngày nhận hàng","⚡ THG xử lý khiếu nại trong vòng 7–20 ngày làm việc","💬 Liên hệ trực tiếp qua Facebook hoặc Hotline để được hỗ trợ nhanh nhất"]}');
INSERT INTO service_blocks (page_slug, kind, position, locale, icon, title, description, payload_json) VALUES ('thg-order', 'policy', 4, 'zh', '📣', '快速透明的索赔处理', '', '{"tag":"索赔流程","items":["⏱️ 丢失货物：发货日起2个月内索赔","⏱️ 损坏/价格争议：收货3天内索赔","⚡ THG在7-20个工作日内解决索赔","💬 通过Facebook或热线直接联系获取最快支持"]}');
